// ─── CONFIGURATION ───────────────────────────────────────
// Edit these values before running the workflow
const CONFIG = {
  // Target niche keywords for Google Maps search
  searchQueries: [
    "e-commerce store",
    "online clothing store",
    "Shopify store",
    "online retail store"
  ],
  // Target cities/regions
  locations: [
    "London, UK",
    "Manchester, UK",
    "New York, USA",
    "Los Angeles, USA"
  ],
  // How many leads per run
  leadsPerRun: 10
};

// Generate search combinations
const combinations = [];
for (const query of CONFIG.searchQueries) {
  for (const location of CONFIG.locations) {
    combinations.push({
      query: `${query} ${location}`,
      niche: query,
      location: location
    });
  }
}

// Shuffle and limit
const shuffled = combinations.sort(() => Math.random() - 0.5);
const selected = shuffled.slice(0, CONFIG.leadsPerRun);

return selected.map(item => ({ json: item }));

// Extract and flatten businesses from Maps response
const results = $json.results || [];

if (results.length === 0) {
  return [];
}

return results.map(place => ({
  json: {
    business_name: place.name,
    address: place.formatted_address,
    place_id: place.place_id,
    rating: place.rating || 'N/A',
    total_ratings: place.user_ratings_total || 0,
    business_status: place.business_status,
    types: (place.types || []).join(', '),
    // Website will be fetched in next step via Place Details
    website: null,
    phone: null
  }
}));

// Merge place details back into business object
const details = $json.result || {};
const prev = $('📋 Extract Business List').item.json;

const website = details.website || null;
const phone = details.formatted_phone_number || details.international_phone_number || null;

// Skip businesses with no website (can't scrape / likely too small)
if (!website) {
  return [];
}

return [{
  json: {
    ...prev,
    website: website,
    phone: phone,
    description: details.editorial_summary?.overview || ''
  }
}];

// Clean HTML and extract meaningful text
const html = $json.data || $json.body || '';
const prev = $('🔗 Merge Business Details').item.json;

// Strip HTML tags
const text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 3000); // Limit to 3000 chars for LLM

return [{
  json: {
    ...prev,
    website_text: text || 'Could not extract website content.'
  }
}];

