// Parse LLM JSON response
const raw = $json.message?.content || $json.choices?.[0]?.message?.content || '';

let analysis;
try {
  // Strip markdown code fences if present
  const clean = raw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(clean);
} catch (e) {
  // Fallback if JSON parse fails
  analysis = {
    pain_points: ['Could not parse pain points'],
    decision_maker_title: 'Founder',
    email_subject: `Quick idea for ${$('🔗 Merge Business Details').item.json.business_name}`,
    email_body: 'Could not generate email. Manual review needed.',
    confidence_score: 0
  };
}

const business = $('🧹 Clean Website Text').item.json;

return [{
  json: {
    // Business info
    business_name: business.business_name,
    website: business.website,
    address: business.address,
    phone: business.phone,
    rating: business.rating,
    // LLM output
    pain_points: analysis.pain_points.join(' | '),
    decision_maker_title: analysis.decision_maker_title,
    email_subject: analysis.email_subject,
    email_body: analysis.email_body,
    confidence_score: analysis.confidence_score,
    // Meta
    status: 'Pending Send',
    created_at: new Date().toISOString(),
    follow_up_count: 0
  }
}];

// Update status in memory after send
// In a real setup, you'd update the Google Sheet row status here
const item = $('📊 Parse LLM Output').item.json;

console.log(`✅ Lead processed: ${item.business_name}`);
console.log(`📧 Email sent to: ${item.decision_maker_title}`);
console.log(`📊 Confidence: ${item.confidence_score}%`);

return [{ json: { ...item, status: 'Sent', sent_at: new Date().toISOString() } }];
